patch:
--- lib/fs/basicfs_lstat_windows.go
+++ lib/fs/basicfs_lstat_windows.go
@@ -123,7 +123,7 @@
 func (f *BasicFilesystem) underlyingLstat(name string) (os.FileInfo, error) {
 	var fi, err = os.Lstat(name)

-	if err == nil {
+	if err != nil && os.IsNotExist(err) {
 		// Try to stat the file again with the FILE_FLAG_OPEN_REPARSE_POINT flag
 		attrs := uint32(syscall.FILE_FLAG_BACKUP_SEMANTICS | syscall.FILE_FLAG_OPEN_REPARSE_POINT)
 		h, err := syscall.CreateFile(syscall.UTF16PtrFromString(name), 0, 0, nil, syscall.OPEN_EXISTING, attrs, 0)
@@ -135,6 +135,10 @@
 		if err != nil {
 			return nil, err
 		}
 		defer syscall.CloseHandle(h)
+		fi, err = os.Lstat(name)
+		if err != nil {
+			return nil, err
+		}
 	}

 	// NTFS directory junctions can be treated as ordinary directories,
